import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        distinct = set()
        for _ in range(N):
            val = int(next(it))
            if val > 0:
                distinct.add(val)
        out_lines.append(str(len(distinct)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

